/**
 * Notification log model — tracks the history of all sent notifications.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationType, NotificationChannel, NotificationStatus } from './notification.js';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  status: NotificationStatus;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  createdAt: Date;
  deliveredAt?: Date;
  error?: string;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: NotificationStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, type, channel, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationChannel, NotificationStatus, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as NotificationStatus,
      subject: record['subject'] as string,
      body: record['body'] as string,
      createdAt: new Date(record['createdAt'] as string),
    };
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }
    if (record['deliveredAt']) {
      log.deliveredAt = new Date(record['deliveredAt'] as string);
    }
    if (record['error']) {
      log.error = record['error'] as string;
    }
    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      subject: entity.subject,
      body: entity.body,
      createdAt: entity.createdAt.toISOString(),
    };
    if (entity.metadata) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }
    if (entity.deliveredAt) {
      record['deliveredAt'] = entity.deliveredAt.toISOString();
    }
    if (entity.error) {
      record['error'] = entity.error;
    }
    return record;
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.createdAt >= startDate && log.createdAt <= endDate,
    );
  }

  query(filter: NotificationHistoryQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (filter.recipient && log.recipient !== filter.recipient) return false;
      if (filter.type && log.type !== filter.type) return false;
      if (filter.channel && log.channel !== filter.channel) return false;
      if (filter.status && log.status !== filter.status) return false;
      if (filter.startDate && log.createdAt < filter.startDate) return false;
      if (filter.endDate && log.createdAt > filter.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — tracks and queries sent notification history.
 *
 * Integrates with the notification flow by subscribing to 'notification:sent'
 * events on the EventBus. Every notification delivery result is logged
 * to the NotificationLogRepository for later querying.
 *
 * Depends on:
 * - EventBus for receiving notification:sent events
 * - NotificationLogRepository for persisting log entries
 * - NotificationService for reading notification details
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent } from '../events/event-types.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationService } from './notification.service.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetNotificationLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private repository: NotificationLogRepository,
    private notificationService: NotificationService,
  ) {
    this.registerEventHandlers();
  }

  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.handleNotificationSent(event);
    });
  }

  private handleNotificationSent(event: NotificationSentEvent): void {
    const notification = this.notificationService
      .getNotifications()
      .find((n) => n.id === event.notificationId);

    if (!notification) {
      this.logger.warn(`Notification not found for logging: ${event.notificationId}`);
      return;
    }

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.notificationId,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      status: event.success ? 'sent' : 'failed',
      subject: notification.subject,
      body: notification.body,
      metadata: notification.metadata,
      createdAt: event.timestamp,
      deliveredAt: event.success ? event.timestamp : undefined,
      error: event.error,
    };

    this.repository.save(log);
    this.logger.info(
      `Logged notification ${event.notificationId} — ${event.success ? 'sent' : 'failed'}`,
    );
  }

  getHistory(query?: NotificationHistoryQuery): NotificationLog[] {
    if (!query) {
      return this.repository.findAll();
    }
    return this.repository.query(query);
  }

  getHistoryForRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  getHistoryByType(type: NotificationHistoryQuery['type']!): NotificationLog[] {
    return this.repository.findByType(type!);
  }

  getHistoryByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  getLogCount(): number {
    return this.repository.count();
  }
}

