import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function createOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2025-06-01T10:00:00Z'),
      updatedAt: new Date('2025-06-01T10:00:00Z'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2025-06-01T10:00:00Z'),
    ...overrides,
  };
}

function createStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date('2025-06-01T10:00:00Z'),
      updatedAt: new Date('2025-06-01T10:00:00Z'),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2025-06-01T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let db: Database;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let repository: NotificationLogRepository;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    repository = new NotificationLogRepository(db);
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    historyService = new NotificationHistoryService(eventBus, repository, notificationService);
    resetNotificationIdCounter();
    resetNotificationLogIdCounter();
  });

  describe('logging sent notifications', () => {
    it('should log a notification after it is sent via adapter', async () => {
      await eventBus.emit(createOrderCreatedEvent());

      const logs = historyService.getHistory();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.deliveredAt).toBeDefined();
    });

    it('should capture subject and body in log', async () => {
      await eventBus.emit(createOrderCreatedEvent());

      const logs = historyService.getHistory();
      expect(logs[0]?.subject).toContain('Order Confirmation');
      expect(logs[0]?.body).toContain('Widget x2');
    });

    it('should capture metadata in log', async () => {
      await eventBus.emit(createOrderCreatedEvent());

      const logs = historyService.getHistory();
      expect(logs[0]?.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit(createStatusChangedEvent());
      await eventBus.emit(createStatusChangedEvent({
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
      }));

      const logs = historyService.getHistory();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      await eventBus.emit(createStatusChangedEvent());

      const logs = historyService.getHistory();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[1]?.type).toBe('order_status_update');
    });
  });

  describe('querying by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      await eventBus.emit(createOrderCreatedEvent({
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [{ productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 15 }],
          total: 15,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
      }));

      const aliceLogs = historyService.getHistoryForRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getHistoryForRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
      expect(bobLogs[0]?.recipient).toBe('bob@example.com');
    });

    it('should return empty array for unknown recipient', async () => {
      await eventBus.emit(createOrderCreatedEvent());

      const logs = historyService.getHistoryForRecipient('unknown@example.com');
      expect(logs).toHaveLength(0);
    });
  });

  describe('querying by type', () => {
    it('should return logs filtered by notification type', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      await eventBus.emit(createStatusChangedEvent());

      const confirmationLogs = historyService.getHistoryByType('order_confirmation');
      expect(confirmationLogs).toHaveLength(1);
      expect(confirmationLogs[0]?.type).toBe('order_confirmation');

      const statusLogs = historyService.getHistoryByType('order_status_update');
      expect(statusLogs).toHaveLength(1);
      expect(statusLogs[0]?.type).toBe('order_status_update');
    });
  });

  describe('querying by date range', () => {
    it('should return logs within a date range', async () => {
      await eventBus.emit(createOrderCreatedEvent({
        timestamp: new Date('2025-06-01T10:00:00Z'),
      }));
      await eventBus.emit(createStatusChangedEvent({
        timestamp: new Date('2025-06-15T10:00:00Z'),
      }));

      const logs = historyService.getHistoryByDateRange(
        new Date('2025-06-01T00:00:00Z'),
        new Date('2025-06-10T00:00:00Z'),
      );
      expect(logs).toHaveLength(1);
    });
  });

  describe('combined query', () => {
    it('should support filtering by multiple criteria', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      await eventBus.emit(createStatusChangedEvent());

      const logs = historyService.getHistory({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order_confirmation');
    });

    it('should return empty when no logs match query', async () => {
      await eventBus.emit(createOrderCreatedEvent());

      const logs = historyService.getHistory({
        recipient: 'alice@example.com',
        type: 'order_status_update',
      });
      expect(logs).toHaveLength(0);
    });

    it('should return all logs when query is empty object', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      await eventBus.emit(createStatusChangedEvent());

      const logs = historyService.getHistory({});
      expect(logs).toHaveLength(2);
    });
  });

  describe('log count', () => {
    it('should return zero when no notifications logged', () => {
      expect(historyService.getLogCount()).toBe(0);
    });

    it('should track the number of logged notifications', async () => {
      await eventBus.emit(createOrderCreatedEvent());
      expect(historyService.getLogCount()).toBe(1);

      await eventBus.emit(createStatusChangedEvent());
      expect(historyService.getLogCount()).toBe(2);
    });
  });
});

