describe('querying by date range', () => {
  it('should return logs within a date range', async () => {
    await eventBus.emit(createOrderCreatedEvent());
    await eventBus.emit(createStatusChangedEvent());

    const now = new Date();
    const oneMinuteAgo = new Date(now.getTime() - 60_000);
    const oneMinuteFromNow = new Date(now.getTime() + 60_000);

    const logs = historyService.getHistoryByDateRange(oneMinuteAgo, oneMinuteFromNow);
    expect(logs).toHaveLength(2);
  });

  it('should exclude logs outside the date range', async () => {
    await eventBus.emit(createOrderCreatedEvent());

    const distantPast = new Date('2020-01-01T00:00:00Z');
    const distantPastEnd = new Date('2020-01-02T00:00:00Z');

    const logs = historyService.getHistoryByDateRange(distantPast, distantPastEnd);
    expect(logs).toHaveLength(0);
  });
});

