+
+  constructor(
+    private eventBus: EventBus,
+    private repository: NotificationLogRepository,
+    private notificationService: NotificationService,
+  ) {
+    this.registerEventHandlers();
+  }
+
+  private registerEventHandlers(): void {
+    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
+      this.handleNotificationSent(event);
+    });
+  }
+
+  private handleNotificationSent(event: NotificationSentEvent): void {
+    const notification = this.notificationService
+      .getNotifications()
+      .find((n) => n.id === event.notificationId);
+
+    if (!notification) {
+      this.logger.warn(`Notification not found for logging: ${event.notificationId}`);
+      return;
+    }
+
+    const log: NotificationLog = {
+      id: generateLogId(),
+      notificationId: event.notificationId,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      type: notification.type,
+      status: event.success ? 'sent' : 'failed',
+      subject: notification.subject,
+      body: notification.body,
+      metadata: notification.metadata,
+      createdAt: event.timestamp,
+      deliveredAt: event.success ? event.timestamp : undefined,
+      error: event.error,
+    };
+
+    this.repository.save(log);
+    this.logger.info(
+      `Logged notification ${event.notificationId} — ${event.success ? 'sent' : 'failed'}`,
+    );
+  }
+
+  getHistory(query?: NotificationHistoryQuery): NotificationLog[] {
+    if (!query) {
+      return this.repository.findAll();
+    }
+    return this.repository.query(query);
+  }
+
+  getHistoryForRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  getHistoryByType(type: NotificationType): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  getHistoryByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  getLogCount(): number {
+    return this.repository.count();
+  }
+}

